### 2.3 事件驱动架构

**设计目标**：解耦模块，实现可观测性

```typescript
// src/core/event-bus.ts
export enum EventType {
  ITERATION_STARTED = 'iteration.started',
  ITERATION_COMPLETED = 'iteration.completed',
  ITERATION_FAILED = 'iteration.failed',
  AGENT_STARTED = 'agent.started',
  AGENT_COMPLETED = 'agent.completed',
  AGENT_FAILED = 'agent.failed',
  GIT_COMMITTED = 'git.committed',
  ERROR_OCCURRED = 'error.occurred',
}

export interface Event {
  type: EventType;
  timestamp: Date;
  data: any;
  metadata?: Record<string, any>;
}

export class EventBus {
  private listeners: Map<EventType, CallableFunction[]> = new Map();

  on(event: EventType, handler: CallableFunction): void {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, []);
    }
    this.listeners.get(event)!.push(handler);
  }

  emit(event: Event): void {
    const handlers = this.listeners.get(event.type) || [];
    handlers.forEach(handler => handler(event));
  }

  // 支持异步处理
  async emitAsync(event: Event): Promise<void> {
    const handlers = this.listeners.get(event.type) || [];
    await Promise.all(handlers.map(handler => handler(event)));
  }
}
```

**事件流示例**：
```typescript
// 在 AutoIterationEngine 中
