  type: EventType.ITERATION_STARTED,
  timestamp: new Date(),
  data: { iterationNumber: 5, task: '添加用户认证' }
});

// 在 Dashboard Server 中监听
eventBus.on(EventType.ITERATION_STARTED, (event) => {
  realtimeService.broadcast('iteration.started', event.data);
});
