### 2.4 并发安全机制

**设计目标**：防止文件冲突，保证数据一致性

```typescript
// src/core/file-lock.ts
export class FileLock {
  private static locks: Map<string, Lock> = new Map();

  static async acquire(filePath: string, timeout = 30000): Promise<Lock> {
    const lockId = `${filePath}-${Date.now()}`;
    const lockFile = `${filePath}.lock`;

    // 使用 mkdir 作为原子操作
    while (true) {
      try {
        fs.mkdirSync(lockFile, { mode: 0o600 });
        const lock = { id: lockId, path: lockFile };
        this.locks.set(filePath, lock);
        return lock;
      } catch (err) {
        // 文件已存在，等待并重试
        await this.sleep(100);
        timeout -= 100;
        if (timeout <= 0) {
          throw new Error(`Lock timeout for ${filePath}`);
        }
      }
    }
  }

  static release(lock: Lock): void {
    fs.rmdirSync(lock.path);
    this.locks.delete(lock.path);
  }
}

// 使用示例
async function safeWriteFile(filePath: string, content: string) {
  const lock = await FileLock.acquire(filePath);
  try {
    fs.writeFileSync(filePath, content);
  } finally {
    FileLock.release(lock);
  }
}
```

### 2.5 错误处理与重试机制

**设计目标**：提高系统鲁棒性

```typescript
// src/core/retry-manager.ts
export class RetryManager {
  static async retry<T>(
    fn: () => Promise<T>,
    options: {
      maxAttempts: number;
      backoffMs: number;
      retryableErrors?: string[];
    }
  ): Promise<T> {
    let lastError: Error;

    for (let attempt = 1; attempt <= options.maxAttempts; attempt++) {
      try {
        return await fn();
      } catch (error) {
        lastError = error as Error;

        if (attempt === options.maxAttempts) break;

        const shouldRetry = 
          !options.retryableErrors || 
          options.retryableErrors.some(e => lastError.message.includes(e));

        if (shouldRetry) {
          const delay = options.backoffMs * attempt;
          await this.sleep(delay);
          continue;
        }

        throw error;
      }
    }

    throw lastError!;
  }
}

// Git 操作重试示例
async function safeGitPush(cwd: string): Promise<void> {
  await RetryManager.retry(
    () => execAsync('git push', { cwd }),
    {
      maxAttempts: 3,
      backoffMs: 2000,
      retryableErrors: ['network', 'timeout', 'connection']
    }
  );
}
```

