// src/base-agent.ts

export interface PerformanceMetrics {
  agentName: string;
  startTime: Date;
  endTime?: Date;
  duration?: number;
  apiCalls: number;
  tokenUsage: number;
  success: boolean;
  error?: string;
}

export abstract class BaseAgent {
  protected metrics: PerformanceMetrics;

  async *execute(prompt: string): AsyncGenerator<any> {
    this.metrics = {
      agentName: this.role,
      startTime: new Date(),
      apiCalls: 0,
      tokenUsage: 0,
      success: false
    };

    try {
      for await (const message of query({ ... })) {
        // 统计 API 调用
        if (message.type === 'tool_result') {
          this.metrics.apiCalls++;
        }

        // 统计 Token 使用
        if (message.type === 'usage') {
          this.metrics.tokenUsage += (message as any).usage?.output_tokens || 0;
        }

        yield message;
      }

      this.metrics.success = true;
    } catch (error) {
      this.metrics.error = String(error);
      throw error;
    } finally {
      this.metrics.endTime = new Date();
      this.metrics.duration = this.metrics.endTime.getTime() - this.metrics.startTime.getTime();

      // 发送到 Dashboard（如果启动）
      this.sendMetricsToDashboard();
    }
  }

  private sendMetricsToDashboard() {
    try {
      const { getServices } = require('../dashboard/server');
      const { metricsService } = getServices();
      metricsService.record(this.metrics);
    } catch {
      // Dashboard 未启动，忽略
    }
  }

  getMetrics(): PerformanceMetrics {
    return this.metrics;
  }
}

// src/dashboard/services/metrics.service.ts

export class MetricsService {
  private metrics: Map<string, PerformanceMetrics[]> = new Map();

  record(metrics: PerformanceMetrics) {
    const key = metrics.agentName;
    if (!this.metrics.has(key)) {
      this.metrics.set(key, []);
    }
    this.metrics.get(key)!.push(metrics);
  }

  getStats(agentName: string) {
    const metrics = this.metrics.get(agentName) || [];
    const avgDuration = metrics.reduce((sum, m) => sum + (m.duration || 0), 0) / metrics.length;
    const successRate = metrics.filter(m => m.success).length / metrics.length;

    return {
      totalCalls: metrics.length,
      avgDuration,
      successRate,
      totalTokens: metrics.reduce((sum, m) => sum + m.tokenUsage, 0)
    };
  }
}
