// src/base-agent.ts

export interface RetryPolicy {
  maxRetries: number;
  initialDelay: number;
  backoffMultiplier: number;
  retryableErrors: string[];
}

export class RetryConfig {
  private static DEFAULT_POLICY: RetryPolicy = {
    maxRetries: 3,
    initialDelay: 1000,
    backoffMultiplier: 2,
    retryableErrors: [
      'ECONNRESET',
      'ETIMEDOUT',
      'ENOTFOUND',
      'rate_limit_exceeded',
      'timeout'
    ]
  };

  static isRetryable(error: Error, policy: RetryPolicy = RetryConfig.DEFAULT_POLICY): boolean {
    return policy.retryableErrors.some(pattern => 
      error.message.includes(pattern)
    );
  }

  static calculateDelay(attempt: number, policy: RetryPolicy = RetryConfig.DEFAULT_POLICY): number {
    return policy.initialDelay * Math.pow(policy.backoffMultiplier, attempt);
  }
}

export abstract class BaseAgent {
  protected retryPolicy: RetryPolicy = RetryConfig.DEFAULT_POLICY;

  setRetryPolicy(policy: Partial<RetryPolicy>): void {
    this.retryPolicy = { ...this.retryPolicy, ...policy };
  }

  async executeWithRetry(prompt: string): Promise<string> {
    let lastError: Error;

    for (let attempt = 0; attempt <= this.retryPolicy.maxRetries; attempt++) {
      try {
        return await this.executeAndCollect(prompt);
      } catch (error) {
        lastError = error as Error;

        // 检查是否可重试
        if (attempt < this.retryPolicy.maxRetries && 
            RetryConfig.isRetryable(lastError, this.retryPolicy)) {
          const delay = RetryConfig.calculateDelay(attempt, this.retryPolicy);
          console.log(`⚠️ ${this.role} 执行失败，${delay}ms 后重试 (${attempt + 1}/${this.retryPolicy.maxRetries})`);

          await this.sleep(delay);
          continue;
        }

        // 不可重试或达到最大重试次数
        console.error(`❌ ${this.role} 执行失败: ${lastError.message}`);
        throw lastError;
      }
    }

    throw lastError!;
  }

  private sleep(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
  }
}
