private validateConfig(config: IterationConfig): ValidationResult {
  const errors: string[] = [];

  // 验证项目路径
  if (!config.projectPath) {
    errors.push('项目路径不能为空');
  } else if (!fs.existsSync(config.projectPath)) {
    errors.push(`项目路径不存在: ${config.projectPath}`);
  } else if (!fs.statSync(config.projectPath).isDirectory()) {
    errors.push(`项目路径不是目录: ${config.projectPath}`);
  }

  // 验证迭代间隔
  if (config.intervalMs < 1000) {
    errors.push('迭代间隔不能小于 1000ms (1秒)');
  }
  if (config.intervalMs > 3600000) {
    errors.push('迭代间隔不能大于 3600000ms (1小时)');
  }

  // 验证最大迭代次数
  if (config.maxIterations < 0) {
    errors.push('最大迭代次数不能为负数');
  }

  return {
    valid: errors.length === 0,
    errors,
  };
}
