private async validateGitEnvironment(): Promise<ValidationResult> {
  const errors: string[] = [];
  const cwd = this.config.projectPath;

  try {
    // 检查是否为 Git 仓库
    childProcess.execSync('git rev-parse --git-dir', { 
      cwd,
      stdio: 'pipe' 
    });
  } catch (error) {
    errors.push('不是有效的 Git 仓库');
    return { valid: false, errors };
  }

  try {
    // 检查远程仓库配置
    childProcess.execSync('git remote -v', { 
      cwd,
      stdio: 'pipe' 
    });
  } catch (error) {
    if (this.config.autoPush) {
      errors.push('启用了 autoPush 但未配置远程仓库');
    }
  }

  // 检查工作目录状态
  try {
    const status = childProcess.execSync('git status --porcelain', { 
      cwd,
      stdio: 'pipe' 
    }).toString();

    if (status.trim().length > 0) {
      errors.push('工作目录有未提交的变更，可能干扰自动迭代');
    }
  } catch (error) {
    errors.push(`无法检查 Git 状态: ${error}`);
  }

  return {
    valid: errors.length === 0,
    errors,
  };
}
