private async gitCommit(task: string): Promise<void> {
  const cwd = this.config.projectPath;

  try {
    // git add
    childProcess.execSync('git add .', { cwd, stdio: 'pipe' });

    // 检查是否有变更
    const status = childProcess.execSync('git diff --cached --name-only', { 
      cwd, 
      stdio: 'pipe' 
    }).toString();

    if (!status.trim()) {
      console.log('ℹ️ 没有需要提交的变更');
      return;
    }

    // git commit
    const commitMessage = `auto: ${task.substring(0, 50)}`;
    childProcess.execSync(`git commit -m "${commitMessage}"`, { 
      cwd, 
      stdio: 'pipe' 
    });

    console.log(`✅ 已提交: ${commitMessage}`);

    // git push
    if (this.config.autoPush) {
      try {
        childProcess.execSync('git push', { cwd, stdio: 'pipe', timeout: 30000 });
        console.log('✅ 已推送到远程');
      } catch (pushError: any) {
        if (pushError.message.includes('auth')) {
          throw new Error('Git 推送失败：认证错误，请检查凭据');
        } else if (pushError.message.includes('network')) {
          throw new Error('Git 推送失败：网络连接问题');
        } else if (pushError.killed) {
          throw new Error('Git 推送超时（30秒），请检查网络');
        } else {
          throw new Error(`Git 推送失败：${pushError.message}`);
        }
      }
    }
  } catch (error: any) {
    if (error.message.includes('auth')) {
      console.error('❌ Git 认证失败');
      throw error;
    }
    throw new Error(`Git 操作失败: ${error.message}`);
  }
}
