import * as fs from 'fs';
import * as path from 'path';
import { ConfigError } from './config-error';

/**
 * 验证器函数集合
 */
export class Validators {
  /**
   * 验证项目路径
   * @param field - 字段名
   * @param projectPath - 项目路径
   * @param mustExist - 是否必须存在
   */
  static validateProjectPath(
    field: string,
    projectPath: string,
    mustExist: boolean = true
  ): void {
    // 检查是否为空
    if (!projectPath || typeof projectPath !== 'string') {
      throw new ConfigError({
        field,
        value: projectPath,
        validationRule: '非空字符串',
        message: '项目路径不能为空'
      });
    }

    // 如果要求必须存在，检查路径
    if (mustExist && !fs.existsSync(projectPath)) {
      throw new ConfigError({
        field,
        value: projectPath,
        validationRule: '路径必须存在',
        message: `项目路径不存在: ${projectPath}`
      });
    }

    // 检查是否为目录
    if (mustExist && !fs.statSync(projectPath).isDirectory()) {
      throw new ConfigError({
        field,
        value: projectPath,
        validationRule: '必须是目录',
        message: `项目路径不是目录: ${projectPath}`
      });
    }
  }

  /**
   * 验证数值范围
   * @param field - 字段名
   * @param value - 数值
   * @param min - 最小值（包含）
   * @param max - 最大值（包含，可选）
   */
  static validateNumberRange(
    field: string,
    value: number,
    min: number,
    max?: number
  ): void {
    // 检查类型
    if (typeof value !== 'number' || isNaN(value)) {
      throw new ConfigError({
        field,
        value,
        validationRule: '必须是有效数字',
        message: `${field} 必须是有效的数字`
      });
    }

    // 检查最小值
    if (value < min) {
      throw new ConfigError({
        field,
        value,
        validationRule: `>= ${min}`,
        message: `${field} 不能小于 ${min}（当前值: ${value}）`
      });
    }

    // 检查最大值
    if (max !== undefined && value > max) {
      throw new ConfigError({
        field,
        value,
        validationRule: `<= ${max}`,
        message: `${field} 不能大于 ${max}（当前值: ${value}）`
      });
    }
  }

  /**
   * 验证枚举值
   * @param field - 字段名
   * @param value - 值
   * @param allowedValues - 允许的值列表
   */
  static validateEnum<T>(
    field: string,
    value: T,
    allowedValues: T[]
  ): void {
    if (!allowedValues.includes(value)) {
      throw new ConfigError({
        field,
        value,
        validationRule: `必须是以下之一: ${allowedValues.join(', ')}`,
        message: `${field} 的值无效。允许的值: ${allowedValues.join(', ')}`
      });
    }
  }

  /**
   * 验证 Git 仓库
   * @param projectPath - 项目路径
   */
  static validateGitRepository(projectPath: string): void {
    const gitDir = path.join(projectPath, '.git');
    if (!fs.existsSync(gitDir)) {
      throw new ConfigError({
        field: 'git',
        value: projectPath,
        validationRule: '必须是 Git 仓库',
        message: `项目不是 Git 仓库（缺少 .git 目录）: ${projectPath}\n` +
                 `提示: 运行 'git init' 初始化仓库`
      });
    }
  }

  /**
   * 验证环境变量
   * @param varNames - 环境变量名列表
   */
  static validateEnvVariables(varNames: string[]): void {
    const missing: string[] = [];

    for (const name of varNames) {
      if (!process.env[name]) {
        missing.push(name);
      }
    }

    if (missing.length > 0) {
      throw new ConfigError({
        field: 'environment',
        value: missing,
        validationRule: '必需的环境变量',
        message: `缺少必需的环境变量: ${missing.join(', ')}\n` +
                 `提示: 在 .env 文件中设置这些变量`
      });
    }
  }
}
```

