import { Validators } from './config/validators';

export class AutoIterationEngine {
  constructor(config: Partial<IterationConfig> = {}) {
    // ===== 新增：配置验证 =====

    // 1. 验证项目路径
    const projectPath = config.projectPath || process.cwd();
    Validators.validateProjectPath('projectPath', projectPath, mustExist: true);

    // 2. 验证迭代间隔
    const intervalMs = config.intervalMs || 60000;
    Validators.validateNumberRange('intervalMs', intervalMs, 1000, 3600000); // 1秒 - 1小时

    // 3. 验证最大迭代次数
    const maxIterations = config.maxIterations ?? 0;
    Validators.validateNumberRange('maxIterations', maxIterations, 0, 1000);

    // 4. 验证权限模式
    const permissionMode = config.permissionMode || 'bypassPermissions';
    Validators.validateEnum('permissionMode', permissionMode, [
      'default', 'acceptEdits', 'bypassPermissions', 'dontAsk'
    ]);

    // 5. 验证布尔值
    const autoCommit = config.autoCommit ?? true;
    const autoPush = config.autoPush ?? true;

    // 6. 如果启用 autoPush，验证 Git 仓库
    if (autoPush) {
      try {
        Validators.validateGitRepository(projectPath);
      } catch (error) {
        console.warn('⚠️ Git 验证失败，将禁用自动推送');
        autoPush = false;
      }
    }

    // 验证通过后，设置配置
    this.config = {
      projectPath,
      intervalMs,
      maxIterations,
      autoCommit,
      autoPush,
      permissionMode,
    };

    console.log('✅ 配置验证通过');
  }
}
