export interface AgentConfig {
  role: string;
  systemPrompt: string;
  allowedTools: string[];
  model?: string;
  // 新增：可配置的上下文参数
  maxHistoryLength?: number;
  maxContentLength?: number;
}

export abstract class BaseAgent {
  protected maxHistoryLength: number;
  protected maxContentLength: number;

  constructor(config: AgentConfig) {
    // ===== 新增：配置验证 =====

    // 1. 验证 role
    if (!config.role || typeof config.role !== 'string') {
      throw new ConfigError({
        field: 'role',
        value: config.role,
        validationRule: '非空字符串',
        message: 'Agent 的 role 字段不能为空'
      });
    }

    // 2. 验证 systemPrompt
    if (!config.systemPrompt || typeof config.systemPrompt !== 'string') {
      throw new ConfigError({
        field: 'systemPrompt',
        value: config.systemPrompt,
        validationRule: '非空字符串',
        message: 'Agent 的 systemPrompt 不能为空'
      });
    }

    // 3. 验证 allowedTools
    if (!Array.isArray(config.allowedTools) || config.allowedTools.length === 0) {
      throw new ConfigError({
        field: 'allowedTools',
        value: config.allowedTools,
        validationRule: '非空数组',
        message: 'Agent 必须有至少一个允许的工具'
      });
    }

    // 4. 验证 maxHistoryLength
    this.maxHistoryLength = config.maxHistoryLength ?? 3;
    Validators.validateNumberRange('maxHistoryLength', this.maxHistoryLength, 1, 10);

    // 5. 验证 maxContentLength
    this.maxContentLength = config.maxContentLength ?? 200;
    Validators.validateNumberRange('maxContentLength', this.maxContentLength, 50, 2000);

    // 验证通过后，设置其他字段
    this.role = config.role;
    this.systemPrompt = config.systemPrompt;
    this.allowedTools = config.allowedTools;
    this.model = config.model || 'glm-5';
  }
}
